import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Ensure buffer size matches user input length or limit it to a safe size
        int bufferSize = Math.min(userInput.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copy a portion of user input into the buffer array
        userInput.getChars(0, bufferSize, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

